// Translating a Figma design to React components
// Figma structure: Frame > Card > {Image, Title, Description, Button}

function Card({ imageSrc, title, description, onAction }) {
  return (
    <div style={{
      borderRadius: 8,        // Figma: corner radius 8px
      padding: 16,            // Figma: auto-layout padding 16
      display: 'flex',        // Figma: auto-layout vertical
      flexDirection: 'column',
      gap: 12,                // Figma: auto-layout gap 12
      boxShadow: '0 2px 8px rgba(0,0,0,0.1)', // Figma: drop shadow
      maxWidth: 320           // Figma: frame width 320
    }}>
      <img src={imageSrc} style={{ borderRadius: 4, width: '100%' }} />
      <h3 style={{ fontSize: 18, fontWeight: 600 }}>{title}</h3>
      <p style={{ fontSize: 14, color: '#666' }}>{description}</p>
      <button style={{ marginTop: 'auto', padding: '8px 16px' }}>
        Learn More
      </button>
    </div>
  );
}

console.log('Card component matches Figma design spec');
```
